// === 입력 정규화 & 컨텍스트 준비 ===
const body = $input.first().json.body || $input.first().json;
const text = (body.text || '').trim();
const userLat = parseFloat(body.lat) || 37.5665;
const userLng = parseFloat(body.lng) || 126.9780;
const landmark = (body.landmark || '').trim();
const userTransportMode = body.transportMode || 'transit';
const categoryGroupCode = (body.categoryGroupCode || '').trim();
const inputType = (body.inputType || 'text').trim();
const userChipRadius = parseInt(body.chipRadius) || 5000;
const lang = (body.lang || 'ko').trim();
const favorites = Array.isArray(body.favorites) ? body.favorites : [];
const recentSearches = Array.isArray(body.recentSearches) ? body.recentSearches : [];
const localTime = body.localTime || new Date().toISOString();
const userId = body.userId || 'anonymous';

// 칩(chip) 클릭은 LLM 건너뜀 → 직접 검색
const skipLLM = inputType === 'chip';

return [{
  json: {
    text, userLat, userLng, landmark, userTransportMode, categoryGroupCode,
    inputType, userChipRadius, lang, favorites, recentSearches, localTime, userId,
    skipLLM,
  }
}];

