={
  "model": "claude-haiku-4-5-20251001",
  "max_tokens": 600,
  "tool_choice": { "type": "tool", "name": "resolve_intent" },
  "tools": [{
    "name": "resolve_intent",
    "description": "사용자 발화에서 검색 의도를 추출합니다.",
    "input_schema": {
      "type": "object",
      "properties": {
        "intent": { "type": "string", "enum": ["search", "navigate_favorite", "ambiguous"] },
        "query": { "type": "string", "description": "카카오 키워드 검색에 쓸 정제된 쿼리. 예: '강남 카페', '키즈존 패밀리 레스토랑'. 지역 힌트 포함 가능." },
