        "spoken": { "type": "string", "description": "TTS로 읽어줄 자연스러운 한 줄 응답. 1순위 + 개수를 포함하면 좋음." }
      },
      "required": ["rankedIndices", "topPickIndex", "topPickReason", "spoken"]
    }
  }],
  "system": "당신은 검색 결과 큐레이터입니다. 사용자의 필터/분위기/의도와 후보들의 카테고리/거리를 종합해 가장 맞는 곳을 추천하세요. 응답 언어는 ko/en에 맞춥니다.",
  "messages": [
    {
      "role": "user",
      "content": "# 원본 발화\n\"{{ $('컨텍스트 준비').first().json.text }}\"\n\n# 의도 필터\n{{ JSON.stringify($json.filters) }}\n\n# 언어: {{ $('컨텍스트 준비').first().json.lang }}\n\n# 후보 (0-based)\n{{ JSON.stringify($json.candidates.map((c,i) => ({i, name:c.name, category:c.category, address:c.address, distance:c.distanceLabel}))) }}"
    }
  ]
}

parameters.jsCode:
// === 최종 응답 조립 (LLM 결과 머지) ===
const prev = $('결과 정규화').first().json;
const llm = $input.first().json;

let curation = { rankedIndices: prev.candidates.map((_,i) => i), topPickIndex: 0, topPickReason: '', spoken: prev.spokenFromIntent || '' };
try {
  const block = (llm.content || []).find(b => b.type === 'tool_use');
  if (block && block.input) curation = Object.assign(curation, block.input);
} catch (e) {}

// rankedIndices에 따라 재정렬
const ordered = curation.rankedIndices
  .map(i => prev.candidates[i])
  .filter(Boolean)
  .map((c, newI) => Object.assign({}, c, { index: newI + 1 }));

// topPickIndex를 새 순서 기준으로 매핑
const newTopIdx = curation.rankedIndices.indexOf(curation.topPickIndex);

return [{ json: {
  candidates: ordered,
  destination: prev.destination,
  transportMode: prev.transportMode,
  spoken: curation.spoken || prev.spokenFromIntent || '',
  topPick: { index: newTopIdx >= 0 ? newTopIdx : 0, reason: curation.topPickReason || '' },
  clarification: '',
}}];

// 큐레이션 없이 그대로 응답 (chip 경로)
const prev = $input.first().json;
return [{ json: {
  candidates: prev.candidates,
  destination: prev.destination,
  transportMode: prev.transportMode,
  spoken: prev.spokenFromIntent || '',
  topPick: null,
  clarification: '',
}}];

// 최종 응답을 그대로 통과 (의도 처리에서 _final=true)
const prev = $input.first().json;
return [{ json: prev._payload || prev }];
